function lec(id, titulo, bloque, explicacion, analogia, ejemplo_malo, ejemplo_bueno, por_que_importa, tip_profesional, verificacion, practica, conexion_sig, conexion_mod) {
  return {
    id, titulo, bloque, tipo: "leccion", duracion_min: 20, xp: 50,
    contenido: {
      teoria: { explicacion, analogia, ejemplo_malo, ejemplo_bueno, por_que_importa, tip_profesional },
      verificacion,
      practica,
      conexion: { siguiente: conexion_sig, modulo_relacionado: conexion_mod }
    }
  };
}

function q(pregunta, opciones, correcta, explicacion_profunda, concepto_reforzado) {
  return { pregunta, opciones, correcta, explicacion_profunda, concepto_reforzado };
}

